      &OutlineEntry;

function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  if (!f.getItemValue('ma_dvcs')) f.setItemValues('ma_dvcs, ten_dvcs%l', [f._unitCode, f._unitName]);
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, id = f.get_id();
  switch (context) {
    case 'Checking':
      var g = f.grid, q = f.getItemValue('quy'), y = f.getItemValue('nam');
      g._quy = q;
      g._nam = y;
      g._dvcs = f.getItemValue('ma_dvcs');
      g._alterTitle = [null, [['%q', q, true], ['%y', y, true]]];
      break;
    default:
      break;
  }
}





